cat > /tmp/binlog-analyzer/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;
using System.IO;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Collect all errors and warnings
var errors = new List<(string Project, string Code, string File, int Line, string Message, string Subcategory)>();
var warnings = new List<(string Project, string Code, string File, int Line, string Message)>();
var projectResults = new Dictionary<string, bool>(); // project -> succeeded

build.VisitAllChildren<BaseNode>(node =>
{
    if (node is Error err)
    {
        string project = GetProjectName(err);
        errors.Add((project, err.Code ?? "", err.File ?? "", err.LineNumber, err.Text ?? err.ToString(), err.Subcategory ?? ""));
    }
    else if (node is Warning warn)
    {
        warnings.Add((GetProjectName(warn), warn.Code ?? "", warn.File ?? "", warn.LineNumber, warn.Text ?? warn.ToString()));
    }
    else if (node is Project proj)
    {
        projectResults[proj.ProjectFile ?? proj.Name] = proj.Succeeded;
    }
});

// Print project results
Console.WriteLine("=== PROJECT BUILD RESULTS ===");
foreach (var kvp in projectResults.OrderBy(k => k.Key))
{
    var status = kvp.Value ? "OK" : "FAILED";
    Console.WriteLine($"  [{status}] {Path.GetFileName(kvp.Key)}");
}

// Print errors grouped by project
Console.WriteLine("\n=== ALL ERRORS ===");
var errorsByProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);
foreach (var group in errorsByProject)
{
    Console.WriteLine($"\n--- Project: {group.Key} ---");
    foreach (var e in group)
    {
        var location = string.IsNullOrEmpty(e.File) ? "" : $" @ {Path.GetFileName(e.File)}:{e.Line}";
        Console.WriteLine($"  [{e.Code}]{location}: {e.Message}");
    }
}

// Print warnings
if (warnings.Any())
{
    Console.WriteLine("\n=== WARNINGS (may be relevant) ===");
    foreach (var w in warnings.Take(30))
    {
        var location = string.IsNullOrEmpty(w.File) ? "" : $" @ {Path.GetFileName(w.File)}:{w.Line}";
        Console.WriteLine($"  [{w.Code}]{location} ({w.Project}): {w.Message}");
    }
    if (warnings.Count > 30)
        Console.WriteLine($"  ... and {warnings.Count - 30} more warnings");
}

// Analyze cascading failures
Console.WriteLine("\n=== DEPENDENCY ANALYSIS ===");
// Look for project reference failures (MSB3202, MSB4181, etc.)
var cascadingCodes = new HashSet<string> { "MSB3202", "MSB4181", "CS0006", "MSB3245" };
var cascadingErrors = errors.Where(e => cascadingCodes.Contains(e.Code) || 
    e.Message.Contains("could not be resolved") ||
    e.Message.Contains("reference required") ||
    e.Code == "MSB3644").ToList();
var rootCauseErrors = errors.Where(e => !cascadingCodes.Contains(e.Code) && 
    !e.Message.Contains("could not be resolved") &&
    !e.Message.Contains("reference required") &&
    e.Code != "MSB3644").ToList();

// Also check for projects that failed and are referenced by other failing projects
var failedProjects = projectResults.Where(p => !p.Value).Select(p => p.Key).ToHashSet();

Console.WriteLine($"\nFailed projects: {failedProjects.Count}");
Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine($"Likely cascading errors: {cascadingErrors.Count}");
Console.WriteLine($"Likely root cause errors: {rootCauseErrors.Count}");

if (rootCauseErrors.Any())
{
    Console.WriteLine("\n=== ROOT CAUSE ERRORS ===");
    foreach (var e in rootCauseErrors)
    {
        var location = string.IsNullOrEmpty(e.File) ? "" : $" @ {Path.GetFileName(e.File)}:{e.Line}";
        Console.WriteLine($"  [{e.Code}]{location} in {e.Project}: {e.Message}");
    }
}

if (cascadingErrors.Any())
{
    Console.WriteLine("\n=== CASCADING / DEPENDENCY ERRORS ===");
    foreach (var e in cascadingErrors)
    {
        var location = string.IsNullOrEmpty(e.File) ? "" : $" @ {Path.GetFileName(e.File)}:{e.Line}";
        Console.WriteLine($"  [{e.Code}]{location} in {e.Project}: {e.Message}");
    }
}

static string GetProjectName(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return Path.GetFileName(p.ProjectFile ?? p.Name ?? "unknown");
        current = current.Parent;
    }
    return "unknown";
}
