using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;
using System.IO;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

var errors = new List<(string Project, string Code, string File, int Line, string Message)>();
var warnings = new List<(string Project, string Code, string File, int Line, string Message)>();

build.VisitAllChildren<BaseNode>(node =>
{
    if (node is Error err)
    {
        string project = GetProjectName(err);
        errors.Add((project, err.Code ?? "", err.File ?? "", err.LineNumber, err.Text ?? err.ToString()));
    }
    else if (node is Warning warn)
    {
        warnings.Add((GetProjectName(warn), warn.Code ?? "", warn.File ?? "", warn.LineNumber, warn.Text ?? warn.ToString()));
    }
});

// Print build succeeded
Console.WriteLine($"Build succeeded: {build.Succeeded}");

// Print errors grouped by project
Console.WriteLine($"\n=== ALL ERRORS ({errors.Count} total) ===");
var errorsByProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);
foreach (var group in errorsByProject)
{
    Console.WriteLine($"\n--- Project: {group.Key} ---");
    foreach (var e in group)
    {
        var location = string.IsNullOrEmpty(e.File) ? "" : $" @ {Path.GetFileName(e.File)}:{e.Line}";
        Console.WriteLine($"  [{e.Code}]{location}: {e.Message}");
    }
}

// Print warnings that might be relevant
var relevantWarningCodes = new HashSet<string> { "CS0618", "NU1603", "NU1605", "MSB3277", "CS0168", "CS0219" };
var relevantWarnings = warnings.Where(w => relevantWarningCodes.Contains(w.Code) || w.Code.StartsWith("NU")).Take(20).ToList();
if (relevantWarnings.Any())
{
    Console.WriteLine($"\n=== RELEVANT WARNINGS ({warnings.Count} total, showing {relevantWarnings.Count}) ===");
    foreach (var w in relevantWarnings)
    {
        var location = string.IsNullOrEmpty(w.File) ? "" : $" @ {Path.GetFileName(w.File)}:{w.Line}";
        Console.WriteLine($"  [{w.Code}]{location} ({w.Project}): {w.Message}");
    }
}

// Dependency/cascading analysis  
Console.WriteLine("\n=== DEPENDENCY / CASCADE ANALYSIS ===");

// Errors that are typically cascading (caused by other project failures)
var cascadingPatterns = new[] { "MSB3202", "MSB4181", "CS0006", "MSB3245", "MSB3644", "MSB3270" };
var cascadingKeywords = new[] { "could not be resolved", "reference required", "depends on .* which did not build" };

var rootCause = new List<(string Project, string Code, string File, int Line, string Message)>();
var cascading = new List<(string Project, string Code, string File, int Line, string Message)>();

foreach (var e in errors)
{
    bool isCascading = cascadingPatterns.Contains(e.Code) ||
        e.Message.Contains("could not be resolved") ||
        e.Message.Contains("reference required") ||
        e.Message.Contains("did not build");

    if (isCascading)
        cascading.Add(e);
    else
        rootCause.Add(e);
}

Console.WriteLine($"\nRoot cause errors: {rootCause.Count}");
Console.WriteLine($"Cascading errors: {cascading.Count}");

if (rootCause.Any())
{
    Console.WriteLine("\n=== ROOT CAUSE ERRORS ===");
    var rcByProject = rootCause.GroupBy(e => e.Project).OrderBy(g => g.Key);
    foreach (var group in rcByProject)
    {
        Console.WriteLine($"\n  Project: {group.Key}");
        foreach (var e in group)
        {
            var location = string.IsNullOrEmpty(e.File) ? "" : $" @ {Path.GetFileName(e.File)}:{e.Line}";
            Console.WriteLine($"    [{e.Code}]{location}: {e.Message}");
        }
    }
}

if (cascading.Any())
{
    Console.WriteLine("\n=== CASCADING ERRORS (caused by root failures) ===");
    foreach (var e in cascading)
    {
        var location = string.IsNullOrEmpty(e.File) ? "" : $" @ {Path.GetFileName(e.File)}:{e.Line}";
        Console.WriteLine($"    [{e.Code}]{location} in {e.Project}: {e.Message}");
    }
}

static string GetProjectName(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return Path.GetFileName(p.ProjectFile ?? p.Name ?? "unknown");
        current = current.Parent;
    }
    return "unknown";
}
