using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;
using System.IO;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Get all projects
Console.WriteLine("=== PROJECTS IN BUILD ===");
build.VisitAllChildren<Project>(proj =>
{
    Console.WriteLine($"  {proj.ProjectFile} (TFM: {proj.TargetFramework})");
});

// Look for NuGet restore info and package references
Console.WriteLine("\n=== NUGET / PACKAGE REFERENCES ===");
build.VisitAllChildren<BaseNode>(node =>
{
    // Look for items that mention Newtonsoft or PackageReference
    if (node is Item item)
    {
        var text = item.ToString();
        if (text.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase) || 
            text.Contains("PackageReference", StringComparison.OrdinalIgnoreCase))
        {
            string project = GetProjectName(node);
            Console.WriteLine($"  [{project}] {text}");
        }
    }
    if (node is Parameter param)
    {
        var text = param.ToString();
        if (text.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase))
        {
            string project = GetProjectName(node);
            Console.WriteLine($"  [{project}] Parameter: {text}");
        }
    }
    if (node is Property prop)
    {
        if (prop.Name?.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase) == true ||
            prop.Value?.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase) == true)
        {
            string project = GetProjectName(node);
            Console.WriteLine($"  [{project}] Property: {prop.Name} = {prop.Value}");
        }
    }
});

// Look for restore messages  
Console.WriteLine("\n=== RESTORE / PACKAGE MESSAGES ===");
build.VisitAllChildren<Message>(msg =>
{
    var text = msg.Text ?? "";
    if (text.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase) ||
        text.Contains("PackageReference", StringComparison.OrdinalIgnoreCase) ||
        (text.Contains("NU") && text.Contains("warning")))
    {
        string project = GetProjectName(msg);
        Console.WriteLine($"  [{project}] {text.Substring(0, Math.Min(text.Length, 200))}");
    }
});

// Check the source file content captured in binlog
Console.WriteLine("\n=== SOURCE FILES REFERENCED ===");
build.VisitAllChildren<BaseNode>(node =>
{
    if (node is SourceFile sf)
    {
        Console.WriteLine($"  {sf.SourceFilePath}");
    }
});

// Check for all items in Services.csproj to see its references
Console.WriteLine("\n=== ITEMS IN Services.csproj (filtered) ===");
build.VisitAllChildren<AddItem>(addItem =>
{
    string project = GetProjectName(addItem);
    if (project.Contains("Services"))
    {
        var name = addItem.Name ?? "";
        if (name == "PackageReference" || name == "Reference" || name == "ProjectReference")
        {
            Console.WriteLine($"  {name}:");
            foreach (var child in addItem.Children.OfType<Item>())
            {
                Console.WriteLine($"    {child.Text}");
            }
        }
    }
});

static string GetProjectName(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return Path.GetFileName(p.ProjectFile ?? p.Name ?? "unknown");
        current = current.Parent;
    }
    return "unknown";
}
