using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;
using System.IO;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Look for the project evaluation to find all evaluated items
Console.WriteLine("=== PROJECT EVALUATION - PackageReference items ===");
build.VisitAllChildren<ProjectEvaluation>(eval =>
{
    var projectName = Path.GetFileName(eval.ProjectFile ?? "");
    Console.WriteLine($"\n  ProjectEvaluation: {projectName}");

    eval.VisitAllChildren<BaseNode>(node =>
    {
        var text = node.ToString();
        if (text.Contains("PackageReference", StringComparison.OrdinalIgnoreCase) && 
            !text.Contains("CheckForDuplicate") &&
            !text.Contains("CollectPackageReferences") &&
            !text.Contains("_ComputePackageReference"))
        {
            Console.WriteLine($"    [{node.GetType().Name}] {text.Substring(0, Math.Min(text.Length, 200))}");
        }
    });
});

// Also look for the csc command line to see what references were passed
Console.WriteLine("\n=== CSC COMMAND LINE FOR Services.csproj ===");
build.VisitAllChildren<Task>(task =>
{
    if (task.Name != "Csc") return;
    string project = GetProjectName(task);
    if (!project.Contains("Services")) return;

    Console.WriteLine($"\n  [{project}] Csc task:");
    task.VisitAllChildren<Message>(msg =>
    {
        var text = msg.Text ?? "";
        if (text.Contains("/reference:") || text.Contains("-reference:"))
        {
            Console.WriteLine($"    {text.Substring(0, Math.Min(text.Length, 400))}");
        }
    });
    // Check Parameters folder
    task.VisitAllChildren<Property>(prop =>
    {
        if (prop.Name == "References" || prop.Name == "Sources" || prop.Name == "CommandLineArgs")
        {
            Console.WriteLine($"    {prop.Name} = {prop.Value?.Substring(0, Math.Min(prop.Value.Length, 500))}");
        }
    });
});

