build.VisitAllChildren<Microsoft.Build.Logging.StructuredLogger.Task>(task =>
{
    if (task.Name != "Csc") return;
    string project = GetProjectName(task);
    if (!project.Contains("Services")) return;

    task.VisitAllChildren<Item>(item =>
    {
        if (item.Name == "Sources" || item.Name == "Source" ||
            item.Text?.EndsWith(".cs") == true)
        {
            Console.WriteLine($"  {item.Text}");
        }
    });

    // Try Parameters folder
