    task.VisitAllChildren<Parameter>(param =>
    {
        if (param.Name == "Sources" || param.Name == "References")
        {
            Console.WriteLine($"  {param.Name}:");
            foreach (var child in param.Children.OfType<Item>())
            {
                Console.WriteLine($"    {child.Text}");
            }
        }
    });
});

