            addItem.Name == "Compile")
        {
            Console.WriteLine($"  [{addItem.Name}] (children: {addItem.Children.Count})");
            foreach (var child in addItem.Children)
            {
                Console.WriteLine($"    {child}");
            }
        }
    });
});

